parameters.jsCode:
const body = $input.first().json.body;
const message = body.message || body.edited_message;
const chat_id = message?.chat?.id;
const text = message?.text || '';
const message_id = message?.message_id;
return [{ json: { chat_id, text, message_id, raw: body } }];

const tenantLookupItems = $('Lookup Tenant').all();
const tenant = tenantLookupItems[0]?.json;
const chat_id = $('Extract Message Data').item.json.chat_id;
const userText = $('Extract Message Data').item.json.text;

const toneDescriptions = {
  direct: 'direct (Alex Hormozi-style — blunt, no fluff)',
  warm: 'warm (encouraging, personal, supportive)',
  professional: 'professional (neutral, structured, data-focused)'
};
const toneDesc = toneDescriptions[tenant.tone] || tenant.tone || 'direct';

const systemPrompt = `You are ${tenant.persona_name || 'Coach'}, an AI accountability coach. Your tone is ${toneDesc}.\n\nTone styles:\n- direct: Alex Hormozi-style. Blunt, no fluff. Call out missed commitments plainly.\n- warm: Encouraging, personal, supportive. Celebrate wins.\n- professional: Neutral, structured. Data-focused.\n\nYour job: Help the user manage their 12-week goals, track daily execution, and stay accountable.\n\nDuring free-form chat: interpret as a goal/memory/progress action. Confirm the action, execute it, then get out of the way. Do not ramble.\n\nWhen user misses a commitment or reports low execution (direct tone): "You said you'd do X. You didn't. What's the plan tomorrow?"\n\n## Tool Rules\n\nFor update/delete actions on goals: ALWAYS call get_goals_overview first to find the goal_id, then call manage_goal with the resolved UUID.\nWhen marking a goal completed: call manage_goal(action: update, status: completed) AND log_progress(log_type: status_change).\nFor vague progress updates: call log_progress(log_type: note).\nWhen showing goals: format as numbered list with progress percentage — never return raw JSON.`;

const historyItems = $input.all();
const history = historyItems
  .map(i => i.json)
  .filter(m => m.role && m.content)
  .reverse();

const messages = [
  ...history.map(m => ({ role: m.role, content: m.content })),
  { role: 'user', content: userText }
];

const tools = [
  {
    name: 'manage_goal',
    description: 'Create, update, or delete a 12-week goal. For update/delete, goal_id is required — call get_goals_overview first if you only have the title.',
    input_schema: {
      type: 'object',
      properties: {
        action: { type: 'string', enum: ['create', 'update', 'delete'] },
        title: { type: 'string' },
        description: { type: 'string' },
        deadline: { type: 'string', description: 'ISO date YYYY-MM-DD' },
        status: { type: 'string', enum: ['active', 'completed', 'paused'] },
        progress_pct: { type: 'integer', minimum: 0, maximum: 100 },
        goal_id: { type: 'string', description: 'UUID — required for update/delete' }
      },
      required: ['action']
    }
  },
  {
    name: 'log_progress',
    description: 'Log a progress note against a goal. Use goal_id (UUID). log_type: progress (numeric update), milestone, note (vague update), status_change (when status changes).',
    input_schema: {
      type: 'object',
      properties: {
        goal_id: { type: 'string' },
        log_type: { type: 'string', enum: ['progress', 'milestone', 'note', 'status_change'] },
        content: { type: 'string' }
      },
      required: ['goal_id', 'log_type', 'content']
    }
  },
  {
    name: 'get_goals_overview',
    description: 'Retrieve all active goals with progress. Call this to show goals OR to find a goal_id before updating/completing/deleting.',
    input_schema: {
      type: 'object',
      properties: {}
    }
  },
  {
    name: 'save_memory',
    description: 'Save something the user wants remembered across sessions.',
    input_schema: {
      type: 'object',
      properties: {
        content: { type: 'string' },
        tags: { type: 'array', items: { type: 'string' } }
      },
      required: ['content']
    }
  },
  {
    name: 'search_memory',
    description: 'Search saved memories by keyword.',
    input_schema: {
      type: 'object',
      properties: {
        query: { type: 'string' }
      },
      required: ['query']
    }
  },
  {
    name: 'web_search',
    description: 'Search the web. Use sparingly — only when user explicitly asks.',
    input_schema: {
      type: 'object',
      properties: {
        query: { type: 'string' }
      },
      required: ['query']
    }
  }
];

return [{
  json: {
    tenant_id: tenant.id,
    tenant_chat_id: chat_id,
    system_prompt: systemPrompt,
    messages: messages,
    tools: tools,
    user_text: userText
  }
}];

