parameters.jsCode:
const response = $input.first().json;
const stopReason = response.stop_reason;
const buildData = $('Build Claude Messages').item.json;

let toolName = 'none';
let toolInput = {};
let toolUseId = null;
let textContent = '';

if (stopReason === 'tool_use') {
  const toolUseBlock = response.content.find(b => b.type === 'tool_use');
  if (toolUseBlock) {
    toolName = toolUseBlock.name;
    toolInput = toolUseBlock.input;
    toolUseId = toolUseBlock.id;
  }
} else {
  const textBlock = response.content.find(b => b.type === 'text');
  if (textBlock) textContent = textBlock.text;
}

return [{
  json: {
    stop_reason: stopReason,
    tool_name: toolName,
    tool_input: toolInput,
    tool_use_id: toolUseId,
    text_content: textContent,
    full_response: response,
    tenant_id: buildData.tenant_id,
    tenant_chat_id: buildData.tenant_chat_id,
    messages: buildData.messages,
    system_prompt: buildData.system_prompt,
    tools: buildData.tools,
    user_text: buildData.user_text
  }
}];

const data = $input.first().json;
const tenant_id = data.tenant_id;
const input = data.tool_input;
const action = input.action;

let method, url, body;

if (action === 'create') {
  method = 'POST';
  url = `${$env.SUPABASE_URL}/rest/v1/goals`;
  body = {
    tenant_id,
    title: input.title,
    description: input.description || null,
    deadline: input.deadline || null,
    status: input.status || 'active',
    progress_pct: input.progress_pct || 0
  };
} else if (action === 'update') {
  method = 'PATCH';
  url = `${$env.SUPABASE_URL}/rest/v1/goals?id=eq.${input.goal_id}`;
  body = {};
  if (input.title) body.title = input.title;
  if (input.description) body.description = input.description;
  if (input.deadline) body.deadline = input.deadline;
  if (input.status) body.status = input.status;
  if (input.progress_pct !== undefined) body.progress_pct = input.progress_pct;
  body.updated_at = new Date().toISOString();
} else if (action === 'delete') {
  method = 'DELETE';
  url = `${$env.SUPABASE_URL}/rest/v1/goals?id=eq.${input.goal_id}`;
  body = null;
}

return [{ json: { ...data, _tool_method: method, _tool_url: url, _tool_body: body } }];

// This node receives tool result from whichever tool branch ran
const item = $input.first().json;

// Pass through all context plus the raw tool result
return [{ json: item }];

const parseData = $('Parse Claude Response').item.json;
const toolResult = $input.first().json;

// Build the extended messages array with tool_use and tool_result turns
const assistantToolUseMessage = {
  role: 'assistant',
  content: parseData.full_response.content
};

// Format tool result content
let toolResultContent;
try {
  // toolResult might be array (Supabase returns arrays) or object
  const rawResult = JSON.parse(JSON.stringify(toolResult));
  // Remove internal _tool_* keys
  const cleaned = Object.fromEntries(
    Object.entries(rawResult).filter(([k]) => !k.startsWith('_tool_') && !['tenant_id','tenant_chat_id','messages','system_prompt','tools','user_text','tool_name','tool_input','tool_use_id','stop_reason','full_response','text_content'].includes(k))
  );
  toolResultContent = JSON.stringify(Array.isArray(rawResult) ? rawResult : cleaned);
} catch (e) {
  toolResultContent = String(toolResult);
}

const toolResultMessage = {
  role: 'user',
  content: [
    {
      type: 'tool_result',
      tool_use_id: parseData.tool_use_id,
      content: toolResultContent
    }
  ]
};

const messages = [
  ...parseData.messages,
  assistantToolUseMessage,
  toolResultMessage
];

return [{
  json: {
    tenant_id: parseData.tenant_id,
    tenant_chat_id: parseData.tenant_chat_id,
    system_prompt: parseData.system_prompt,
    tools: parseData.tools,
    messages: messages,
    user_text: parseData.user_text
  }
}];

const response = $input.first().json;
const secondCallData = $('Build Second Claude Request').item.json;

const textBlock = response.content?.find(b => b.type === 'text');
const finalText = textBlock ? textBlock.text : 'Done.';

return [{
  json: {
    tenant_id: secondCallData.tenant_id,
    tenant_chat_id: secondCallData.tenant_chat_id,
    response: finalText,
    user_text: secondCallData.user_text,
    messages: secondCallData.messages
  }
}];

// Claude responded directly without a tool call — route to send reply
const data = $input.first().json;
return [{
  json: {
    tenant_id: data.tenant_id,
    tenant_chat_id: data.tenant_chat_id,
    response: data.text_content,
    user_text: data.user_text,
    messages: data.messages
  }
}];

const chat_id = String($('Extract Message Data').item.json.chat_id);
const text = $('Extract Message Data').item.json.text;

// Use workflow staticData to persist onboarding state
const staticData = $getWorkflowStaticData('global');
if (!staticData.onboarding) staticData.onboarding = {};

let state = staticData.onboarding[chat_id] || { step: 0 };
let reply = '';
let done = false;
let tenantData = null;

if (state.step === 0) {
  // Fresh /start — ask for persona name
  state.step = 1;
  reply = "Hey! I'm your accountability coach. What should I call myself? (e.g. Coach, Alex, Mentor)";
} else if (state.step === 1) {
  // Received persona name
  state.persona_name = text.trim();
  state.step = 2;
  reply = `Got it, I'll go by ${state.persona_name}. What tone do you prefer?\n\n1. Direct — Alex Hormozi style, no fluff\n2. Warm — Encouraging and personal\n3. Professional — Structured and neutral`;
} else if (state.step === 2) {
  // Received tone selection
  const toneMap = { '1': 'direct', '2': 'warm', '3': 'professional', 'direct': 'direct', 'warm': 'warm', 'professional': 'professional' };
  state.tone = toneMap[text.trim().toLowerCase()] || 'direct';
  const twelveWeeks = new Date();
  twelveWeeks.setDate(twelveWeeks.getDate() + 84);
  const deadlineStr = twelveWeeks.toLocaleDateString('en-GB', { day: 'numeric', month: 'long', year: 'numeric' });
  state.step = 3;
  state.goals = [];
  reply = `${state.tone.charAt(0).toUpperCase() + state.tone.slice(1)} it is.\n\nWhat's your first 12-week goal? Be specific — what's the outcome you want by ${deadlineStr}?`;
} else if (state.step === 3) {
  // Received first goal
  state.goals.push(text.trim());
  state.step = 4;
  reply = 'Got it. Any other goals? (up to 2 more, or say "done" to continue)';
} else if (state.step === 4) {
  // Optionally collect more goals
  if (text.trim().toLowerCase() === 'done' || state.goals.length >= 3) {
    state.step = 5;
    reply = 'What time do you usually start work? (e.g. 07:30)';
  } else {
    state.goals.push(text.trim());
    if (state.goals.length >= 3) {
      state.step = 5;
      reply = 'What time do you usually start work? (e.g. 07:30)';
    } else {
      reply = `Added. Any more goals? (${3 - state.goals.length} remaining, or say "done")`;
    }
  }
} else if (state.step === 5) {
  // Received work start time — complete onboarding
  state.work_start_time = text.trim();
  done = true;

  const goalsList = state.goals.map(g => `• ${g}`).join('\n');
  reply = `You're live.\n\nGoals set:\n${goalsList}\n\nFirst briefing: tomorrow at ${state.work_start_time}\nCheck-in: daily at 17:00\n\nSee you then.`;

  tenantData = {
    persona_name: state.persona_name,
    tone: state.tone,
    work_start_time: state.work_start_time,
    goals: state.goals,
    chat_id: chat_id
  };

  // Clear onboarding state
  delete staticData.onboarding[chat_id];
} else {
  reply = 'Something went wrong with onboarding. Send /start to begin again.';
  delete staticData.onboarding[chat_id];
}

if (!done) {
  staticData.onboarding[chat_id] = state;
}

return [{
  json: {
    chat_id: parseInt(chat_id),
    reply,
    done,
    tenant_data: tenantData
  }
}];

const tenantRow = $input.first().json[0] || $input.first().json;
const tenant_id = tenantRow.id;
const onboardingData = $('Onboarding State Machine').item.json;
const goals = onboardingData.tenant_data.goals;

const twelveWeeks = new Date();
twelveWeeks.setDate(twelveWeeks.getDate() + 84);
const deadline = twelveWeeks.toISOString().split('T')[0];

const goalRows = goals.map(title => ({
  tenant_id,
  title,
  status: 'active',
  progress_pct: 0,
  deadline
}));

return [{ json: { tenant_id, goal_rows: goalRows, chat_id: onboardingData.chat_id, reply: onboardingData.reply } }];

