parameters.jsCode:
// Determine if this message is a check-in reply.
// Conditions: tenant has checkin_sent_at today AND checkin_completed_at is null
// AND message looks like a check-in reply (numbers, 'all', 'none').

const tenantLookupItems = $('Lookup Tenant').all();
const tenant = tenantLookupItems[0]?.json;
const userText = $('Extract Message Data').item.json.text?.trim().toLowerCase() || '';

if (!tenant) {
  return [{ json: { is_checkin_reply: false } }];
}

// Check if today's daily_priorities row has checkin_sent_at set but checkin_completed_at null
const today = new Date().toISOString().split('T')[0];

// Look at the tenant's checkin status — we'll check Supabase in the next node
// For now, determine if text pattern matches a check-in reply
const isNumberPattern = /^[\d\s,]+$/.test(userText); // e.g. "1 3", "1,2,3", "2"
const isAllNone = userText === 'all' || userText === 'none';
const looksLikeCheckin = isNumberPattern || isAllNone;

return [{
  json: {
    tenant_id: tenant.id,
    tenant_chat_id: tenant.telegram_chat_id,
    tenant_tone: tenant.tone || 'direct',
    persona_name: tenant.persona_name || 'Coach',
    user_text: userText,
    today,
    looksLikeCheckin
  }
}];

const dailyRow = $input.first().json;
const checkinData = $('Check-in Reply Routing').item.json;
const userText = checkinData.user_text;

const priorities = dailyRow.priorities || [];
const total = priorities.length;

// Parse the reply
let completedIndices = new Set();

if (userText === 'all') {
  for (let i = 0; i < total; i++) completedIndices.add(i);
} else if (userText === 'none') {
  // No indices — all false
} else {
  // Parse numbers like "1 3" or "1,2,3" or "2" — 1-indexed
  const nums = userText.split(/[\s,]+/).map(n => parseInt(n.trim(), 10)).filter(n => !isNaN(n));
  nums.forEach(n => {
    if (n >= 1 && n <= total) completedIndices.add(n - 1); // convert to 0-indexed
  });
}

// Update priorities with completed flags
const updatedPriorities = priorities.map((p, i) => ({
  ...p,
  completed: completedIndices.has(i)
}));

// Calculate execution score: completed / total * 100, round to 1 decimal
const completedCount = completedIndices.size;
const executionScore = total > 0 ? Math.round((completedCount / total) * 1000) / 10 : 0;

// Build acknowledgment message based on tone and score
const tone = checkinData.tenant_tone;
const persona = checkinData.persona_name;
let ackMessage;

if (executionScore >= 80) {
  if (tone === 'warm') {
    ackMessage = `${completedCount}/${total} — that's a solid day. Keep building on that momentum.`;
  } else if (tone === 'professional') {
    ackMessage = `Execution: ${executionScore}%. ${completedCount}/${total} priorities completed. Strong result.`;
  } else { // direct
    ackMessage = `${completedCount}/${total}. Good. Keep that up.`;
  }
} else if (executionScore >= 50) {
  if (tone === 'warm') {
    ackMessage = `${completedCount}/${total} today. Progress. What will you close out tomorrow?`;
  } else if (tone === 'professional') {
    ackMessage = `Execution: ${executionScore}%. ${completedCount}/${total} priorities completed. Room to improve.`;
  } else { // direct
    ackMessage = `${completedCount}/${total}. Decent, not great. What's on the list tomorrow?`;
  }
} else {
  // Below 50% — callout
  const missedItems = updatedPriorities
    .filter(p => !p.completed)
    .map(p => p.text)
    .slice(0, 2); // name at most 2 missed items
  const missedText = missedItems.length > 0 ? ` You didn't do: ${missedItems.join(', ')}.` : '';

  if (tone === 'warm') {
    ackMessage = `${completedCount}/${total} today.${missedText} What got in the way, and what's the plan tomorrow?`;
  } else if (tone === 'professional') {
    ackMessage = `Execution: ${executionScore}%. ${completedCount}/${total} completed.${missedText} Plan corrections for tomorrow.`;
  } else { // direct
    ackMessage = `${completedCount}/${total}.${missedText} You said you'd do it. What's the plan tomorrow?`;
  }
}

return [{
  json: {
    tenant_id: checkinData.tenant_id,
    tenant_chat_id: checkinData.tenant_chat_id,
    today: checkinData.today,
    updatedPriorities,
    executionScore,
    completedCount,
    total,
    ackMessage
  }
}];
